const now = new Date();
const twoWeeksAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
const epochSince = Math.floor(twoWeeksAgo.getTime() / 1000);
const runDate = now.toISOString().split('T')[0];

// Clear any previous static data
const staticData = $getWorkflowStaticData('global');
Object.keys(staticData).forEach(k => delete staticData[k]);

return [{
  json: {
    runId: `ci-${runDate}`,
    runTimestamp: now.toISOString(),
    runDate,
    epochSince,
    gmailAfter: twoWeeksAgo.toISOString().split('T')[0],
    sheetId: 'YOUR_GOOGLE_SHEET_ID'
  }
}];

// ═══ DEDUPLICATION ═══
// 1. Within-run: merge same event across sources by title similarity
// 2. Cross-run: mark signals that appeared in previous digests

const input = $input.all()[0].json;
const signals = input.signals || [];
const sd = $getWorkflowStaticData('global');
const prevSignals = sd.previousSignals || [];

// ── Jaccard word similarity ──
function wordSimilarity(a, b) {
  const wa = new Set(String(a).toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(w => w.length > 2));
  const wb = new Set(String(b).toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(w => w.length > 2));
  if (wa.size === 0 || wb.size === 0) return 0;
  let intersection = 0;
  for (const w of wa) { if (wb.has(w)) intersection++; }
  return intersection / (wa.size + wb.size - intersection);
}

// ── Step 1: Within-run dedup ──
const merged = [];
const used = new Set();
for (let i = 0; i < signals.length; i++) {
  if (used.has(i)) continue;
  const sig = { ...signals[i], sources_all: [{ name: signals[i].source, url: signals[i].url }] };
  for (let j = i + 1; j < signals.length; j++) {
    if (used.has(j)) continue;
    if (wordSimilarity(sig.title, signals[j].title) > 0.5) {
      sig.sources_all.push({ name: signals[j].source, url: signals[j].url });
      if (signals[j].summary.length > sig.summary.length) sig.summary = signals[j].summary;
      used.add(j);
    }
  }
  merged.push(sig);
}

// ── Step 2: Cross-run dedup ──
const final = [];
for (const sig of merged) {
  let previouslyReported = false;
  let firstSeen = null;
  for (const prev of prevSignals) {
    if (wordSimilarity(sig.title, prev.Title || prev.title || '') > 0.45) {
      previouslyReported = true;
      firstSeen = prev.Date || prev.date || 'previous run';
      break;
    }
  }
  sig.previouslyReported = previouslyReported;
  sig.firstSeen = firstSeen;
  // Only include if new OR if it's genuinely different content
  if (!previouslyReported) {
    final.push(sig);
  } else {
    // Check if summary has substantially new info vs previous
    const prevMatch = prevSignals.find(p => wordSimilarity(sig.title, p.Title || p.title || '') > 0.45);
    if (prevMatch && wordSimilarity(sig.summary, prevMatch.Summary || prevMatch.summary || '') < 0.3) {
      sig.title = 'Update: ' + sig.title;
      final.push(sig);
    }
    // Otherwise: filtered out (duplicate)
  }
}

sd.dedupStats = { raw: signals.length, afterWithinDedup: merged.length, afterCrossDedup: final.length, filtered: merged.length - final.length };

return [{ json: { signals: final, stats: sd.stats, dedupStats: sd.dedupStats } }];

