let gmailMessages = [];
try { gmailMessages = $('Read Gmail Alerts').all().map(i => i.json).filter(r => !r.error && !r._empty); } catch(e) { gmailMessages = []; }

// Changedetection data - parse responseFormat:text wrapper
let cdWatches = {};
try {
  const cdRaw = $('Fetch CD Watches').first().json;
  let cdParsed = cdRaw;
  if (cdRaw && cdRaw.data && typeof cdRaw.data === 'string') {
    try { cdParsed = JSON.parse(cdRaw.data); } catch(e) { cdParsed = {}; }
  }
  if (cdParsed && !cdParsed.error && typeof cdParsed === 'object') {
    cdWatches = cdParsed;
  }
} catch(e) { cdWatches = {}; }

const allSignals = [];
const errors = [];
const stats = {urls_fetched:0,url_errors:0,cd_changes:0,gmail_alerts:0,news_items:0,regulatory_items:0,filtered_noise:0};

function matchCompetitor(text) {
  const lower = String(text).toLowerCase();
  for (const c of COMPETITORS) {
    if (lower.includes(c.name.toLowerCase())) return c.name;
    for (const alt of (c.altNames||[])) {
      if (lower.includes(alt.toLowerCase())) return c.name;
    }
    if (c.domain && lower.includes(c.domain)) return c.name;
  }
  return null;
}

function simpleHash(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h) + str.charCodeAt(i);
    h |= 0;
  }
  return h.toString(16);
}

function tryJson(s) {
  if (typeof s !== 'string') return null;
  try { return JSON.parse(s); } catch(e) { return null; }
}

const INDUSTRY_KEYWORDS = ['YOUR_INDUSTRY_TERM', 'YOUR_KEYWORD_1', 'YOUR_KEYWORD_2',
  // Add 10-15 keywords that define your space.
  // Examples for different industries:
  // Project management: 'project planning', 'resource allocation', 'gantt', 'agile'
  // HR tech: 'talent acquisition', 'employee engagement', 'HRIS', 'onboarding'
  // Cybersecurity: 'compliance', 'risk management', 'governance', 'audit', 'penetration testing'
  'YOUR_REGULATION_1', 'YOUR_REGULATION_2'];

const REGULATORY_EXCLUDE = ['cryptocurrency', 'real estate', 'sports',
  'entertainment', 'weather', 'recipe', 'horoscope'];
  // Add terms that cause false positives for YOUR competitors.
  // Example: if a competitor is called "Monday", exclude 'mountain climbing', 'hiking'

function isRelevantNews(signal) {
  const text = (signal.title + ' ' + (signal.summary || '')).toLowerCase();
  const comp = COMPETITORS.find(function(c) { return c.name === signal.competitor; });
  if (!comp) return true;
  const names = [comp.name].concat(comp.altNames||[]).filter(Boolean).map(function(s) { return s.toLowerCase(); });
  if (comp.domain) names.push(comp.domain.toLowerCase());
  var mentionsCompetitor = names.some(function(n) { return text.includes(n); });
  if (mentionsCompetitor) return true;
  return INDUSTRY_KEYWORDS.some(function(kw) { return text.includes(kw); });
}

function isRelevantRegulatory(signal) {
  const text = (signal.title + ' ' + (signal.summary || '')).toLowerCase();
  if (REGULATORY_EXCLUDE.some(function(kw) { return text.includes(kw); })) return false;
  return ['compliance', 'risk', 'governance', 'regulation',
    // Add your industry-specific regulatory terms here
    'audit', 'data protection'].some(function(kw) { return text.includes(kw); });
}

const twoWeeksAgo = new Date(Date.now() - 14*24*60*60*1000);

for (const [uuid, w] of Object.entries(cdWatches)) {
  if (typeof w !== 'object' || !w) continue;
  if (w.last_changed && w.last_changed > 0) {
    const cd = new Date(w.last_changed * 1000);
    if (cd > twoWeeksAgo) {
      stats.cd_changes++;
      allSignals.push({
        source: 'changedetection',
        competitor: matchCompetitor(w.title || w.link || w.url || '') || (w.title || w.link || w.url || uuid).split(' - ')[0] || 'Unknown',
        title: 'Page change: ' + (w.title || w.link || w.url || uuid),
        summary: 'Content changed (detected by changedetection.io)',
        url: w.link || w.url || '',
        timestamp: cd.toISOString()
      });
    }
  }
}

for (let i = 0; i < items.length; i++) {
  const m = meta[i] || {};
  const d = items[i].json;
  const type = m.type || 'unknown';
  const competitor = m.competitor || 'Unknown';
  const body = d.data || '';

  if (d.error) {
    errors.push(type + ' ' + (m.url || '') + ': ' + (typeof d.error === 'object' ? d.error.message || JSON.stringify(d.error).substring(0, 100) : String(d.error)));
    if (type === 'url_monitor') stats.url_errors++;
    continue;
  }

  try {
    if (type === 'url_monitor') {
      stats.urls_fetched++;
      const hash = simpleHash(String(body));
      const sr = stateRows.find(function(r) { return r.URL === m.url; });
      if (sr && sr.ContentHash && sr.ContentHash !== String(hash)) {
        allSignals.push({
          source: 'url_monitor',
          competitor: competitor,
          title: 'Website change: ' + m.url,
          summary: 'Content hash changed',
          url: m.url,
          timestamp: new Date().toISOString()
        });
      }
      if (!sd.urlHashes) sd.urlHashes = {};
      sd.urlHashes[m.url] = {competitor: competitor, hash: String(hash)};
    }
    else if (type === 'news_search' || type === 'regulatory' || type === 'self_search') {
      const data = tryJson(body);
      if (data && data.results) {
        for (const r of data.results.slice(0, 10)) {
          const src = type === 'regulatory' ? 'regulatory' : type === 'self_search' ? 'self_search' : 'news_search';
          const signal = {
            source: src,
            competitor: competitor,
            title: r.title || '',
            summary: r.content || '',
            url: r.url || '',
            timestamp: new Date().toISOString()
          };
          if (src === 'news_search' && !isRelevantNews(signal)) {
            stats.filtered_noise++;
            continue;
          }
          if (src === 'regulatory' && !isRelevantRegulatory(signal)) {
            stats.filtered_noise++;
            continue;
          }
          if (type === 'news_search') stats.news_items++;
          if (type === 'regulatory') stats.regulatory_items++;
          allSignals.push(signal);
        }
      }
    }
  } catch(e) {
    errors.push('Processing ' + type + ': ' + e.message);
  }
}

for (const msg of gmailMessages) {
  const subject = msg.subject || msg.Subject || '';
  const body = msg.snippet || msg.textPlain || '';
  if (!subject && !body) continue;
  const from = msg.from || msg.From || '';
  const date = msg.date || msg.Date || new Date().toISOString();
  const comp = matchCompetitor(subject + ' ' + body);
  const allText = body + ' ' + (msg.textHtml || '');
  const urlMatch = allText.match(/https?:\/\/[^\s\"'<>]+/g);
  const firstUrl = urlMatch ? (urlMatch.find(function(u) { return u.indexOf('google.com/alerts') === -1 && u.indexOf('f5bot.com') === -1; }) || urlMatch[0]) : '';
  stats.gmail_alerts++;
  allSignals.push({
    source: 'gmail_alert',
    competitor: comp || 'Unknown',
    title: subject,
    summary: body.substring(0, 300),
    url: firstUrl || '',
    timestamp: date,
    alertType: from.indexOf('f5bot') !== -1 ? 'f5bot' : 'google_alert'
  });
}

sd.stats = {competitors_monitored: COMPETITORS.length, urls_fetched: stats.urls_fetched, url_errors: stats.url_errors, cd_changes: stats.cd_changes, gmail_alerts: stats.gmail_alerts, news_items: stats.news_items, regulatory_items: stats.regulatory_items, filtered_noise: stats.filtered_noise};
sd.previousSignals = prevSignals;

return [{json: {
  signals: allSignals,
  stats: sd.stats,
  signalCount: allSignals.length,
  debugErrors: errors.slice(0, 10)
}}];
